# Generating secure session IDs in different languages

# Python - Using secrets module (cryptographically secure)
import secrets

def generate_session_id():
    # Generate 32 random bytes (256 bits)
    random_bytes = secrets.token_bytes(32)
    # Convert to hexadecimal string (64 characters)
    session_id = random_bytes.hex()
    return session_id

# Alternative: base64 encoded URL-safe string
def generate_session_id_urlsafe():
    # Generate URL-safe base64 encoded string
    return secrets.token_urlsafe(32)  # 32 bytes of randomness

# PHP - Using random_bytes (cryptographically secure)
function generateSessionId() {
    // Generate 32 random bytes
    $randomBytes = random_bytes(32);
    // Convert to hexadecimal
    return bin2hex($randomBytes);
}

# JavaScript/Node.js - Using crypto module
const crypto = require('crypto');

function generateSessionId() {
    // Generate 32 random bytes
    return crypto.randomBytes(32).toString('hex');
}

